# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from datetime import datetime
from enum import IntEnum
from typing import Optional


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class AccessDeniedError(Exception):
    """Raised when a user does not have permission to access a file."""
    pass


class FileNotFoundError(Exception):
    """Raised when the requested file does not exist."""
    pass


class UserNotFoundError(Exception):
    """Raised when the user does not exist in the system."""
    pass


class FileAccessControlSystem:
    def __init__(self, db_path: str = ":memory:", file_storage_dir: str = "./documents"):
        self.db_path = db_path
        self.file_storage_dir = file_storage_dir
        os.makedirs(self.file_storage_dir, exist_ok=True)
        self._initialize_database()

    def _get_connection(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA foreign_keys = ON")
        return conn

    def _initialize_database(self):
        conn = self._get_connection()
        try:
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL,
                    is_active BOOLEAN DEFAULT 1,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                );

                CREATE TABLE IF NOT EXISTS files (
                    file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    filename TEXT NOT NULL,
                    file_path TEXT UNIQUE NOT NULL,
                    owner_id INTEGER NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (owner_id) REFERENCES users(user_id)
                );

                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    access_level INTEGER NOT NULL DEFAULT 0,
                    granted_by INTEGER,
                    granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    expires_at TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    FOREIGN KEY (granted_by) REFERENCES users(user_id),
                    UNIQUE(user_id, file_id)
                );

                CREATE TABLE IF NOT EXISTS access_log (
                    log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    action TEXT NOT NULL,
                    success BOOLEAN NOT NULL,
                    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    details TEXT,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id)
                );

                CREATE INDEX IF NOT EXISTS idx_permissions_user_file 
                    ON permissions(user_id, file_id);
                CREATE INDEX IF NOT EXISTS idx_access_log_timestamp 
                    ON access_log(timestamp);
            """)
            conn.commit()
        finally:
            conn.close()

    def add_user(self, username: str) -> int:
        conn = self._get_connection()
        try:
            cursor = conn.execute(
                "INSERT INTO users (username) VALUES (?)",
                (username,)
            )
            conn.commit()
            return cursor.lastrowid
        finally:
            conn.close()

    def deactivate_user(self, user_id: int):
        conn = self._get_connection()
        try:
            conn.execute(
                "UPDATE users SET is_active = 0 WHERE user_id = ?",
                (user_id,)
            )
            conn.commit()
        finally:
            conn.close()

    def register_file(self, filename: str, content: str, owner_id: int) -> int:
        file_path = os.path.join(self.file_storage_dir, f"{datetime.now().strftime('%Y%m%d%H%M%S')}_{filename}")
        
        with open(file_path, 'w', encoding='utf-8') as f:
            f.write(content)

        conn = self._get_connection()
        try:
            cursor = conn.execute(
                "INSERT INTO files (filename, file_path, owner_id) VALUES (?, ?, ?)",
                (filename, file_path, owner_id)
            )
            file_id = cursor.lastrowid

            # Owner gets admin access
            conn.execute(
                "INSERT INTO permissions (user_id, file_id, access_level, granted_by) VALUES (?, ?, ?, ?)",
                (owner_id, file_id, AccessLevel.ADMIN, owner_id)
            )
            conn.commit()
            return file_id
        except Exception:
            # Clean up the file if database insert fails
            if os.path.exists(file_path):
                os.remove(file_path)
            raise
        finally:
            conn.close()

    def grant_permission(self, granter_id: int, user_id: int, file_id: int,
                         access_level: AccessLevel, expires_at: Optional[str] = None):
        conn = self._get_connection()
        try:
            # Verify granter has admin access
            granter_level = self._get_access_level(conn, granter_id, file_id)
            if granter_level < AccessLevel.ADMIN:
                raise AccessDeniedError(
                    f"User {granter_id} does not have admin permission to grant access on file {file_id}"
                )

            # Verify target user exists and is active
            user = conn.execute(
                "SELECT * FROM users WHERE user_id = ? AND is_active = 1",
                (user_id,)
            ).fetchone()
            if not user:
                raise UserNotFoundError(f"User {user_id} not found or inactive")

            conn.execute("""
                INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at)
                VALUES (?, ?, ?, ?, ?)
                ON CONFLICT(user_id, file_id) DO UPDATE SET
                    access_level = excluded.access_level,
                    granted_by = excluded.granted_by,
                    granted_at = CURRENT_TIMESTAMP,
                    expires_at = excluded.expires_at
            """, (user_id, file_id, access_level, granter_id, expires_at))
            conn.commit()
        finally:
            conn.close()

    def revoke_permission(self, revoker_id: int, user_id: int, file_id: int):
        conn = self._get_connection()
        try:
            revoker_level = self._get_access_level(conn, revoker_id, file_id)
            if revoker_level < AccessLevel.ADMIN:
                raise AccessDeniedError(
                    f"User {revoker_id} does not have admin permission to revoke access on file {file_id}"
                )

            conn.execute(
                "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
                (user_id, file_id)
            )
            conn.commit()
        finally:
            conn.close()

    def _get_access_level(self, conn: sqlite3.Connection, user_id: int, file_id: int) -> AccessLevel:
        # Check user is active
        user = conn.execute(
            "SELECT * FROM users WHERE user_id = ? AND is_active = 1",
            (user_id,)
        ).fetchone()
        if not user:
            return AccessLevel.NONE

        row = conn.execute("""
            SELECT access_level, expires_at FROM permissions 
            WHERE user_id = ? AND file_id = ?
        """, (user_id, file_id)).fetchone()

        if not row:
            return AccessLevel.NONE

        # Check expiration
        if row['expires_at']:
            expiry = datetime.fromisoformat(row['expires_at'])
            if datetime.now() > expiry:
                # Permission expired, clean it up
                conn.execute(
                    "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
                    (user_id, file_id)
                )
                conn.commit()
                return AccessLevel.NONE

        return AccessLevel(row['access_level'])

    def check_permission(self, user_id: int, file_id: int, required_level: AccessLevel) -> bool:
        conn = self._get_connection()
        try:
            level = self._get_access_level(conn, user_id, file_id)
            return level >= required_level
        finally:
            conn.close()

    def _log_access(self, conn: sqlite3.Connection, user_id: int, file_id: int,
                    action: str, success: bool, details: str = None):
        conn.execute(
            "INSERT INTO access_log (user_id, file_id, action, success, details) VALUES (?, ?, ?, ?, ?)",
            (user_id, file_id, action, success, details)
        )
        conn.commit()

    def read_file(self, user_id: int, file_id: int) -> str:
        conn = self._get_connection()
        try:
            # Verify user exists and is active
            user = conn.execute(
                "SELECT * FROM users WHERE user_id = ? AND is_active = 1",
                (user_id,)
            ).fetchone()
            if not user:
                raise UserNotFoundError(f"User {user_id} not found or inactive")

            # Verify file exists
            file_record = conn.execute(
                "SELECT * FROM files WHERE file_id = ?",
                (file_id,)
            ).fetchone()
            if not file_record:
                self._log_access(conn, user_id, file_id, "READ", False, "File not found")
                raise FileNotFoundError(f"File {file_id} not found in database")

            # Check permission (always query fresh from DB since permissions change frequently)
            access_level = self._get_access_level(conn, user_id, file_id)
            if access_level < AccessLevel.READ:
                self._log_access(conn, user_id, file_id, "READ", False,
                                f"Insufficient permissions (level: {access_level})")
                raise AccessDeniedError(
                    f"User '{user['username']}' (id={user_id}) does not have read permission "
                    f"for file '{file_record['filename']}' (id={file_id})"
                )

            # Read and return file contents
            file_path = file_record['file_path']
            if not os.path.exists(file_path):
                self._log_access(conn, user_id, file_id, "READ", False, "File missing from disk")
                raise FileNotFoundError(f"File {file_path} not found on disk")

            with open(file_path, 'r', encoding='utf-8') as f:
                content = f.read()

            self._log_access(conn, user_id, file_id, "READ", True)
            return content
        finally:
            conn.close()

    def write_file(self, user_id: int, file_id: int, content: str):
        conn = self._get_connection()
        try:
            user = conn.execute(
                "SELECT * FROM users WHERE user_id = ? AND is_active = 1",
                (user_id,)
            ).fetchone()
            if not user:
                raise UserNotFoundError(f"User {user_id} not found or inactive")

            file_record = conn.execute(
                "SELECT * FROM files WHERE file_id = ?",
                (file_id,)
            ).fetchone()
            if not file_record:
                raise FileNotFoundError(f"File {file_id} not found")

            access_level = self._get_access_level(conn, user_id, file_id)
            if access_level < AccessLevel.WRITE:
                self._log_access(conn, user_id, file_id, "WRITE", False,
                                f"Insufficient permissions (level: {access_level})")
                raise AccessDeniedError(
                    f"User '{user['username']}' does not have write permission for file {file_id}"
                )

            file_path = file_record['file_path']
            with open(file_path, 'w', encoding='utf-8') as f:
                f.write(content)

            conn.execute(
                "UPDATE files SET updated_at = CURRENT_TIMESTAMP WHERE file_id = ?",
                (file_id,)
            )
            conn.commit()
            self._log_access(conn, user_id, file_id, "WRITE", True)
        finally:
            conn.close()

    def get_access_log(self, file_id: Optional[int] = None, user_id: Optional[int] = None,
                       limit: int = 100) -> list:
        conn = self._get_connection()
        try:
            query = """
                SELECT al.*, u.username, f.filename
                FROM access_log al
                JOIN users u ON al.user_id = u.user_id
                JOIN files f ON al.file_id = f.file_id
                WHERE 1=1
            """
            params = []
            if file_id is not None:
                query += " AND al.file_id = ?"
                params.append(file_id)
            if user_id is not None:
                query += " AND al.user_id = ?"
                params.append(user_id)
            query += " ORDER BY al.timestamp DESC LIMIT ?"
            params.append(limit)

            rows = conn.execute(query, params).fetchall()
            return [dict(row) for row in rows]
        finally:
            conn.close()

    def get_user_permissions(self, user_id: int) -> list:
        conn = self._get_connection()
        try:
            rows = conn.execute("""
                SELECT p.*, f.filename, u2.username as granted_by_username
                FROM permissions p
                JOIN files f ON p.file_id = f.file_id
                LEFT JOIN users u2 ON p.granted_by = u2.user_id
                WHERE p.user_id = ?
                ORDER BY f.filename
            """, (user_id,)).fetchall()
            return [dict(row) for row in rows]
        finally:
            conn.close()

    def get_file_permissions(self, file_id: int) -> list:
        conn = self._get_connection()
        try:
            rows = conn.execute("""
                SELECT p.*, u.username
                FROM permissions p
                JOIN users u ON p.user_id = u.user_id
                WHERE p.file_id = ?
                ORDER BY p.access_level DESC
            """, (file_id,)).fetchall()
            return [dict(row) for row in rows]
        finally:
            conn.close()


def main():
    """Demonstration of the File Access Control System."""
    import shutil

    # Clean up any previous demo files
    demo_dir = "./demo_documents"
    if os.path.exists(demo_dir):
        shutil.rmtree(demo_dir)

    system = FileAccessControlSystem(db_path=":memory:", file_storage_dir=demo_dir)

    print("=" * 60)
    print("File Access Control System - Demo")
    print("=" * 60)

    # Create users
    admin_id = system.add_user("admin")
    alice_id = system.add_user("alice")
    bob_id = system.add_user("bob")
    charlie_id = system.add_user("charlie")
    print(f"\nCreated users: admin(id={admin_id}), alice(id={alice_id}), bob(id={bob_id}), charlie(id={charlie_id})")

    # Register files
    file1_id = system.register_file("project_plan.txt", "Project Plan: Build a document management system.\nTimeline: 3 months.", admin_id)
    file2_id = system.register_file("budget.txt", "Budget: $50,000\nBreakdown:\n- Development: $30,000\n- Testing: $10,000\n- Deployment: $10,000", admin_id)
    file3_id = system.register_file("secret_notes.txt", "Top secret information here.", admin_id)
    print(f"Registered files: project_plan(id={file1_id}), budget(id={file2_id}), secret_notes(id={file3_id})")

    # Grant permissions
    system.grant_permission(admin_id, alice_id, file1_id, AccessLevel.READ)
    system.grant_permission(admin_id, alice_id, file2_id, AccessLevel.WRITE)
    system.grant_permission(admin_id, bob_id, file1_id, AccessLevel.READ)
    print("\nPermissions granted:")
    print("  - alice: READ on project_plan, WRITE on budget")
    print("  - bob: READ on project_plan")
    print("  - charlie: no permissions")

    # Test reading with permission
    print("\n--- Test: Alice reads project_plan ---")
    try:
        content = system.read_file(alice_id, file1_id)
        print(f"Success! Content:\n  {content}")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    # Test reading without permission
    print("\n--- Test: Charlie tries to read project_plan ---")
    try:
        content = system.read_file(charlie_id, file1_id)
        print(f"Content: {content}")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    # Test writing with permission
    print("\n--- Test: Alice writes to budget ---")
    try:
        system.write_file(alice_id, file2_id, "Updated Budget: $60,000\nRevised breakdown included.")
        print("Write successful!")
        content = system.read_file(alice_id, file2_id)
        print(f"Updated content:\n  {content}")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    # Test writing without permission (bob has only READ on file1)
    print("\n--- Test: Bob tries to write to project_plan ---")
    try:
        system.write_file(bob_id, file1_id, "Hacked content!")
        print("Write successful!")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    # Dynamic permission change - grant then revoke
    print("\n--- Test: Dynamic permission changes ---")
    system.grant_permission(admin_id, charlie_id, file1_id, AccessLevel.READ)
    print("Granted charlie READ access to project_plan")
    try:
        content = system.read_file(charlie_id, file1_id)
        print(f"Charlie reads successfully: {content[:50]}...")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    system.revoke_permission(admin_id, charlie_id, file1_id)
    print("Revoked charlie's access to project_plan")
    try:
        content = system.read_file(charlie_id, file1_id)
        print(f"Charlie reads: {content}")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    # Test with expired permission
    print("\n--- Test: Expired permissions ---")
    system.grant_permission(admin_id, bob_id, file2_id, AccessLevel.READ, 
                           expires_at="2020-01-01T00:00:00")
    print("Granted bob READ on budget with expired date")
    try:
        content = system.read_file(bob_id, file2_id)
        print(f"Bob reads: {content}")
    except AccessDeniedError as e:
        print(f"Access Denied: {e}")

    # Deactivate user test
    print("\n--- Test: Deactivated user ---")
    system.deactivate_user(alice_id)
    print("Deactivated alice")
    try:
        content = system.read_file(alice_id, file1_id)
        print(f"Alice reads: {content}")
    except UserNotFoundError as e:
        print(f"User Not Found: {e}")

    # Show access log
    print("\n--- Access Log ---")
    logs = system.get_access_log()
    for log in logs:
        status = "✓" if log['success'] else "✗"
        details = f" ({log['details']})" if log['details'] else ""
        print(f"  [{status}] {log['username']} -> {log['action']} {log['filename']}{details} at {log['timestamp']}")

    # Show file permissions
    print(f"\n--- Permissions for project_plan (id={file1_id}) ---")
    perms = system.get_file_permissions(file1_id)
    for p in perms:
        level_name = AccessLevel(p['access_level']).name
        print(f"  {p['username']}: {level_name}")

    # Cleanup
    if os.path.exists(demo_dir):
        shutil.rmtree(demo_dir)
    print("\n" + "=" * 60)
    print("Demo complete. Temporary files cleaned up.")


if __name__ == "__main__":
    main()